  "integration_assessment": {
    "component_interactions": [
      {
        "from": "KYC Service",
        "to": "Onfido API",
        "status": "risk",
        "issue": "Synchronous blocking call with no circuit breaker and no fallback. Onfido downtime directly becomes registration downtime. The team's 99.95% internal SLA is mathematically impossible when the critical-path dependency (Onfido) only guarantees 99.9%. The service ceiling IS the weakest link."
      },
      {
        "from": "User Registration Flow",
        "to": "KYC Service",
        "status": "risk",
        "issue": "Registration is fully blocked until KYC completes. A 3s p99 from Onfido (plus network) means registration latency is dominated by an external call with no async option. Under Onfido degradation, users see 5s timeouts then a hard 503."
      },
      {
        "from": "/health endpoint",
        "to": "Onfido API",
        "status": "risk",
        "issue": "Health check probes Onfido reachability. This couples the service's liveness to an external dependency. If Onfido is slow or down, the orchestrator (k8s/ECS) may restart or drain healthy instances, causing a cascading outage of the KYC service itself — amplifying the blast radius."
      }
    ],
    "contract_compliance": "Onfido integration appears functionally correct. However, the operational contract is violated: the team promises 99.95% uptime but architecturally can only deliver ≤99.9% (Onfido's ceiling). This is a 4.38-hour/year gap in allowed downtime (99.95% = 4.38h vs 99.9% = 8.76h).",
    "data_flow_integrity": "Synchronous request-response with Onfido. No evidence of idempotency keys on Onfido calls — retries after timeout could create duplicate KYC checks and billing events. Data flow is otherwise straightforward."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "Confirm PII (identity documents, SSN, DOB) is NOT logged in structured JSON payloads — KYC data is highly regulated",
        "No mention of correlation/request IDs for tracing a single registration through KYC"
      ]
    },
    "metrics": {
      "coverage": "gaps",
      "gaps": [
        "No kyc_check_errors_total broken down by error type (timeout, 4xx, 5xx, network) — critical for distinguishing Onfido outage from bad requests",
        "No circuit breaker state metric (open/closed/half-open) since circuit breaker doesn't exist yet",
        "No metric for registration-blocked-by-kyc wait time from the user's perspective",
        "No Onfido quota/rate-limit tracking"
      ]
    },
    "tracing": {
      "coverage": "gaps",
      "gaps": [
        "No mention of distributed tracing spans for the Onfido external call",
        "Cannot trace a user's registration latency breakdown (internal vs Onfido) without explicit span instrumentation"
      ]
    },
    "debugging_capability": "Moderate. kyc_duration_histogram and kyc_checks_total provide baseline visibility, but an on-call engineer at 3am cannot quickly distinguish 'Onfido is slow' from 'our service is slow' without error-type breakdown and tracing. PII leak risk in logs is a regulatory concern that needs verification."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Onfido full outage (within their 0.1% allowed downtime)",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Implement a degraded mode. Options: (1) Accept registration provisionally and complete KYC asynchronously via webhook/queue, marking user as 'pending_kyc' with limited platform access. (2) Queue the KYC check and retry with exponential backoff. Either approach decouples registration availability from Onfido availability."
      },
      {
        "scenario": "Onfido partial degradation (p99 > 3s, approaching 5s timeout)",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Add a circuit breaker (e.g., 50% error rate over 30s window → open circuit). Without it, every request pays the full 5s timeout, exhausting connection pools and threads, turning Onfido slowness into KYC service death."
      },
      {
        "scenario": "Onfido rate limiting (429 responses)",
        "handling": "unhandled",
        "recommendation": "Add rate-limit-aware retry with backoff respecting Retry-After headers. Without this, a traffic spike triggers Onfido rate limiting which triggers 503s for all users."
      },
      {
        "scenario": "Health check cascading failure",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Split health check into liveness (is the process healthy?) and readiness (can it serve traffic?). Onfido reachability should only affect readiness, NEVER liveness. Current design risks container restarts during Onfido outages."
      },
      {
        "scenario": "Duplicate KYC checks on timeout + retry",
        "handling": "unhandled",
        "recommendation": "Use idempotency keys on Onfido API calls to prevent duplicate identity checks and double-billing."
      }
    ],
    "retry_config": "No retry policy mentioned. A single failed Onfido call results in immediate 503 to the user. Recommend 1-2 retries with exponential backoff for 5xx/timeout errors only (not 4xx).",
    "timeout_config": "5s timeout on Onfido call. Acceptable given Onfido's 3s p99, but needs a circuit breaker to prevent thread exhaustion when timeouts become the norm during degradation.",
    "circuit_breakers": "NONE. This is the single biggest operational risk. Without a circuit breaker, Onfido degradation cascades into full KYC service failure, exhausting thread pools and connection pools as every request waits 5s to fail.",
    "graceful_degradation": "NONE. The service has a binary mode: working or 503. No provisional acceptance, no queuing, no async fallback. This guarantees that Onfido's downtime becomes the platform's registration downtime."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous image. Acceptable for the KYC service itself, but does not mitigate the core risk — the previous image has the same Onfido dependency with no fallback.",
    "monitoring_coverage": "Partial. Basic metrics exist (counters, histograms) but lack error-type breakdown and circuit breaker state. Alerting strategy not defined — no mention of alerts on Onfido error rate spikes or latency degradation.",
    "on_call_documentation": "Not mentioned. On-call engineer needs a runbook covering: (1) How to identify Onfido outage vs internal issue, (2) What to communicate to users, (3) Manual override procedures if any, (4) Escalation path to Onfido support.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": ["Message queue or async job processor for deferred KYC checks in degraded mode"],
      "new_queues_topics": ["kyc-pending-checks queue for async fallback processing"],
      "config_changes": ["Circuit breaker configuration (thresholds, window, recovery)", "Retry policy configuration", "Split liveness/readiness probe configuration"],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": true,
      "large_table_impact": false,
      "details": "No database migrations mentioned. If async fallback is implemented, a 'pending_kyc' user state will need schema support."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "infrastructure_gap",
      "issue": "SLA arithmetic violation: team promises 99.95% but architecture ceiling is 99.9%",
      "reason": "Synchronous Onfido dependency with no fallback makes the team's SLA mathematically unachievable. The service needs an async fallback path (queue + deferred KYC) to decouple registration uptime from Onfido uptime. This requires new infrastructure (message queue, job processor, user state for 'pending_kyc').",
      "routed_to": "Coach K"
    },
    {
      "type": "infrastructure_gap",
      "issue": "No circuit breaker on critical external dependency",
      "reason": "Without a circuit breaker, Onfido partial degradation (slow responses) causes thread/connection pool exhaustion in the KYC service, turning a vendor issue into a full platform registration outage. Circuit breaker config and potentially a library addition are required.",
      "routed_to": "Coach K"
    },
    {
      "type": "integration_risk",
      "issue": "Health check design couples service liveness to external dependency",
      "reason": "The /health endpoint checks Onfido reachability. If the orchestrator uses this for liveness probes, Onfido downtime triggers container restarts — amplifying the outage. Must split into liveness (process health) and readiness (can serve traffic) probes.",
      "routed_to": "Coach K"
    }
  ],

  "confidence": {
    "level": 90,
    "high_confidence_areas": [
      "SLA math: 99.95% target is provably unachievable with 99.9% synchronous dependency and no fallback",
      "Circuit breaker absence is a critical operational risk — this is well-understood failure mode",
      "Health check coupling to external dependency is a known anti-pattern"
    ],
    "low_confidence_areas": [
      "PII logging compliance — cannot verify without seeing actual log output configuration",
      "Exact retry/idempotency behavior — no code reviewed, assessing from description only",
